+        // Hangul Syllables
+        | 0xAC00..=0xD7AF
+        // Fullwidth Forms
+        | 0xFF01..=0xFF60
+        | 0xFFE0..=0xFFE6
+        // Katakana / Hiragana
+        | 0x3040..=0x309F
+        | 0x30A0..=0x30FF
+        // CJK Symbols and Punctuation
+        | 0x3000..=0x303F
+        // Enclosed CJK Letters
+        | 0x3200..=0x33FF
+        // CJK Compatibility
+        | 0xFE30..=0xFE4F
+        // Common emoji (Miscellaneous Symbols + Dingbats + Emoticons + Transport)
+        | 0x1F300..=0x1F9FF
+        // Regional indicator symbols (flags)
+        | 0x1F1E0..=0x1F1FF
